#include <stdio.h>
#include <stdlib.h>

#define MAXN 100005

int leftChild[MAXN];
int rightChild[MAXN];
int isChild[MAXN];

void preorder(int node) {
    if (node == 0) return;
    printf("%d ", node);
    preorder(leftChild[node]);
    preorder(rightChild[node]);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        for (int i = 1; i <= N; ++i) {
            leftChild[i] = rightChild[i] = isChild[i] = 0;
        }
        for (int i = 0; i < N-1; ++i) {
            int p, c; char dir;
            scanf("%d %d %c", &p, &c, &dir);
            if (dir == 'L') leftChild[p] = c; else rightChild[p] = c;
            isChild[c] = 1;
        }
        int root = 1;
        for (int i = 1; i <= N; ++i) if (!isChild[i]) { root = i; break; }
        preorder(root);
        printf("\n");
    }
    return 0;
}

