import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int[] left = new int[N + 1];
            int[] right = new int[N + 1];
            boolean[] isChild = new boolean[N + 1];
            for (int i = 0; i < N - 1; i++) {
                int p = fs.nextInt();
                int c = fs.nextInt();
                char dir = fs.next().charAt(0);
                if (dir == 'L') left[p] = c; else right[p] = c;
                isChild[c] = true;
            }
            int root = 1;
            for (int i = 1; i <= N; i++) if (!isChild[i]) { root = i; break; }
            Deque<Integer> stack = new ArrayDeque<>();
            stack.push(root);
            boolean first = true;
            while (!stack.isEmpty()) {
                int node = stack.pop();
                if (first) { out.append(node); first = false; } else out.append(' ').append(node);
                if (right[node] != 0) stack.push(right[node]);
                if (left[node] != 0) stack.push(left[node]);
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }

    // Fast scanner for Java
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream is) { in = new BufferedInputStream(is); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && c <= ' ') {}
            while (c != -1 && c > ' ') {
                sb.append((char) c);
                c = readByte();
            }
            return sb.toString();
        }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
    }
}

