const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
if (input.length === 0) process.exit(0);
const T = parseInt(input[idx++], 10);
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = parseInt(input[idx++], 10);
  const left = new Array(N + 1).fill(0);
  const right = new Array(N + 1).fill(0);
  const isChild = new Array(N + 1).fill(false);
  for (let i = 0; i < N - 1; i++) {
    const p = parseInt(input[idx++], 10);
    const c = parseInt(input[idx++], 10);
    const dir = input[idx++];
    if (dir === 'L') left[p] = c; else right[p] = c;
    isChild[c] = true;
  }
  let root = 1;
  for (let i = 1; i <= N; i++) if (!isChild[i]) { root = i; break; }
  const stack = [root];
  const order = [];
  while (stack.length) {
    const node = stack.pop();
    order.push(node);
    if (right[node]) stack.push(right[node]);
    if (left[node]) stack.push(left[node]);
  }
  outputs.push(order.join(' '));
}
console.log(outputs.join('\n'));
